class Solution:
    def isReachableAtTime(self, sx, sy, fx, fy, t):
        if t == 0:
            return sx == fx and sy == fy
        current = {(sx, sy)}
        for _ in range(t):
            nxt = set()
            for (x, y) in current:
                for dx in (-1, 0, 1):
                    for dy in (-1, 0, 1):
                        if dx == 0 and dy == 0:
                            continue
                        nxt.add((x + dx, y + dy))
            current = nxt
        return (fx, fy) in current

