class Solution:
    def isReachableAtTime(self, sx: int, sy: int, fx: int, fy: int, t: int) -> bool:
        dx = abs(sx - fx)
        dy = abs(sy - fy)
        dist = max(dx, dy)
        if dist == 0:
            return t != 1
        return t >= dist

